LOG_FILE = Path("debug_run.log")

def log(msg: str, level: str = "INFO"):
    ts = datetime.datetime.now().strftime("%H:%M:%S.%f")[:-3]
    line = f"[{ts}] [{level}] {msg}"
    print(line, flush=True)
    with LOG_FILE.open("a", encoding="utf-8") as f:
        f.write(line + "\n")

def log_exc(label: str):
    tb = traceback.format_exc()
    log(f"{label}\n{tb}", level="ERROR")

def cleanup_screenshots():
    png_files = list(Path(".").glob("*.png"))
    if png_files:
        for f in png_files:
            try:
                f.unlink()
            except Exception:
                pass
        log(f"🗑️  {len(png_files)} screenshot(s) anteriores eliminados")
    else:
        log("🗑️  No había screenshots previos")

